<template><el-card><template #header><b>新建流动人口居住登记申请</b></template><el-form ref="refForm" :model="form" :rules="rules" label-width="130px" style="max-width:760px"><el-form-item label="人员" prop="personId"><PersonSelect v-model="form.personId"/></el-form-item><el-form-item label="来源区划" prop="sourceRegionCode"><el-input v-model="form.sourceRegionCode"/></el-form-item><el-form-item label="来源地址"><el-input v-model="form.sourceAddress"/></el-form-item><el-form-item label="当前区划" prop="currentRegionCode"><el-input v-model="form.currentRegionCode"/></el-form-item><el-form-item label="当前居住地址" prop="currentAddress"><el-input v-model="form.currentAddress"/></el-form-item><el-form-item label="居住事由"><el-select v-model="form.residenceReasonCode"><el-option v-for="x in reasons" :key="x" :value="x"/></el-select></el-form-item><el-form-item label="居住证明"><el-select v-model="form.residenceProofType"><el-option v-for="x in proofs" :key="x" :value="x"/></el-select></el-form-item><el-form-item label="到达/计划离开"><el-date-picker v-model="dates" type="daterange" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="联系电话"><el-input v-model="form.applicantPhone"/></el-form-item><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="申请原因"><el-input v-model="form.reason" type="textarea"/></el-form-item><el-form-item><el-button @click="$router.back()">取消</el-button><el-button type="primary" @click="save">保存草稿</el-button></el-form-item></el-form></el-card></template>
<script setup>import{reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import PersonSelect from'../../components/business/PersonSelect.vue';import{createFloatingApplication}from'../../api/floatingResidence';const router=useRouter(),refForm=ref(),dates=ref([]),reasons=['EMPLOYMENT','STUDY','FAMILY','BUSINESS','OTHER_APPROVED'],proofs=['RENTAL_CONTRACT','PROPERTY_CERTIFICATE','EMPLOYER_ACCOMMODATION','SCHOOL_ACCOMMODATION','HOST_CONFIRMATION','OTHER_APPROVED'];const form=reactive({personId:null,sourceRegionCode:'',sourceAddress:'',currentRegionCode:'',currentAddress:'',residenceReasonCode:'EMPLOYMENT',residenceProofType:'RENTAL_CONTRACT',applicantPhone:'',title:'流动人口居住登记申请',reason:'',remark:''});const rules={personId:[{required:true}],sourceRegionCode:[{required:true}],currentRegionCode:[{required:true}],currentAddress:[{required:true}]};async function save(){await refForm.value.validate();form.arrivalDate=dates.value?.[0];form.plannedLeaveDate=dates.value?.[1];const r=await createFloatingApplication(form);ElMessage.success('草稿已创建');router.push(`/floating-registrations/applications/${r.applicationId}`)}</script>
